SELECT id, company_name AS companyName, contact_name AS contactName, email, phone, inquiry_type AS inquiryType, status, created_at AS createdAt FROM inquiry
status = #{status}
AND ( company_name LIKE CONCAT('%', #{keyword}, '%') OR contact_name LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY created_at ASC ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM inquiry
status = #{status}
AND ( company_name LIKE CONCAT('%', #{keyword}, '%') OR contact_name LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%') )
